import * as fs from "fs";
import * as path from "path";
const PDFDocument = require("pdfkit");
const { createCanvas, registerFont } = require("canvas");
const pdfjsLib = require("pdfjs-dist/legacy/build/pdf.js");
import { pathToFileURL } from "url";
import { t, translateDepartment } from "../utils/i18n";
import { OrderDetail, OrderItem } from "../models/order.schema";
import { pino } from "pino";

const logger = pino();

/**
 * PDFService - Handles all PDF generation and rendering operations.
 *
 * Extracted from OrderService to follow Single Responsibility Principle.
 * Responsible for:
 * - Marina Summary PDF (full order overview)
 * - Fabric Order PDF (kumaş sipariş raporu)
 * - PDF-to-Image conversion (pdfjs + canvas)
 */
export class PDFService {
  private static instance: PDFService;

  private readonly fontRegular: string;
  private readonly fontBold: string;
  private readonly defaultFont: string;
  private readonly boldFont: string;

  constructor() {
    // __dirname = dist/services/ → ../../src/assets/fonts (dev) veya ../assets/fonts (prod)
    const distFonts = path.join(__dirname, "..", "assets", "fonts");
    const srcFonts = path.join(process.cwd(), "src", "assets", "fonts");
    const fontsDir = fs.existsSync(distFonts) ? distFonts : srcFonts;
    this.fontRegular = path.join(fontsDir, "Roboto-Regular.ttf");
    this.fontBold = path.join(fontsDir, "Roboto-Bold.ttf");
    this.defaultFont = fs.existsSync(this.fontRegular)
      ? this.fontRegular
      : "Helvetica";
    this.boldFont = fs.existsSync(this.fontBold)
      ? this.fontBold
      : "Helvetica-Bold";
  }

  public static getInstance(): PDFService {
    if (!PDFService.instance) {
      PDFService.instance = new PDFService();
    }
    return PDFService.instance;
  }

  /**
   * Bir sipariş kalemi için resim Buffer'ını çözer.
   * imageBuffer varsa onu kullanır, yoksa imageUrl üzerinden yerel diskten yükler.
   */
  private async ensureImageBuffer(
    item: OrderItem,
  ): Promise<Buffer | undefined> {
    if (item.imageBuffer) return item.imageBuffer;

    if (item.imageUrl) {
      try {
        // imageUrl genellikle "/data/images/..." formatındadır.
        // Başındaki / işaretini temizle ve process.cwd() ile birleştir.
        const relativePath = item.imageUrl.startsWith("/")
          ? item.imageUrl.substring(1)
          : item.imageUrl;
        const absolutePath = path.join(process.cwd(), relativePath);

        if (fs.existsSync(absolutePath)) {
          return fs.readFileSync(absolutePath);
        } else {
          logger.warn(`Resim dosyası diskte bulunamadı: ${absolutePath}`);
        }
      } catch (error) {
        logger.error(
          { err: error },
          `Resim diskten yüklenirken hata oluştu: ${item.imageUrl}`,
        );
      }
    }

    return undefined;
  }

  // ─── Marina Summary PDF ─────────────────────────────────────────────────────

  /**
   * Generates the full Marina Summary PDF for an order.
   * Contains all items with images, departments, and worker assignments.
   */
  async generateMarinaSummaryPDF(order: OrderDetail): Promise<Buffer> {
    return new Promise((resolve, reject) => {
      const doc = new PDFDocument({ margin: 30, size: "A4" });
      const chunks: Buffer[] = [];

      doc.on("data", (chunk: Buffer) => chunks.push(chunk));
      doc.on("end", () => resolve(Buffer.concat(chunks)));
      doc.on("error", (err: Error) => reject(err));

      // --- HEADER ---
      doc.rect(30, 30, 535, 60).fill("#1a1a1a");
      doc
        .font(this.boldFont)
        .fontSize(18)
        .fillColor("#ffffff")
        .text(t("pdf_marina_header", "ru"), 30, 45, {
          align: "center",
          width: 535,
        });
      doc
        .font(this.defaultFont)
        .fontSize(10)
        .fillColor("#cccccc")
        .text(t("system_coordinator_title", "ru"), 30, 70, {
          align: "center",
          width: 535,
        });

      doc.moveDown(3);
      let currentY = 110;

      // --- CUSTOMER INFO ---
      doc
        .fillColor("#000")
        .font(this.boldFont)
        .fontSize(12)
        .text(`${t("customer_label", "ru")}: `, 30, currentY, {
          continued: true,
        });
      doc.font(this.defaultFont).text(order.customerName);

      doc
        .font(this.boldFont)
        .text(`${t("order_label", "ru")}: `, 30, currentY + 15, {
          continued: true,
        });
      doc.font(this.defaultFont).text(order.orderNumber);

      doc
        .font(this.boldFont)
        .text(`${t("delivery_label", "ru")}: `, 30, currentY + 30, {
          continued: true,
        });
      doc.font(this.defaultFont).text(order.deliveryDate);

      currentY += 60;

      // --- TABLE HEADER ---
      const colImg = 35;
      const colX = [95, 210, 350, 440];
      doc.rect(30, currentY, 535, 20).fill("#f2f2f2").stroke("#ccc");
      doc.fillColor("#000").font(this.boldFont).fontSize(9);
      doc.text("Фото", colImg, currentY + 5);
      doc.text(t("pdf_table_product", "ru"), colX[0], currentY + 5);
      doc.text(t("pdf_table_details", "ru"), colX[1], currentY + 5);
      doc.text(t("dept_label", "ru"), colX[2], currentY + 5);
      doc.text(t("worker_label", "ru"), colX[3], currentY + 5);

      currentY += 20;

      // --- ROWS ---
      const processRows = async () => {
        for (let index = 0; index < order.items.length; index++) {
          const item = order.items[index];
          const rowHeight = 70;
          if (currentY + rowHeight > 750) {
            doc.addPage();
            currentY = 30;
            doc.rect(30, currentY, 535, 20).fill("#f2f2f2").stroke("#ccc");
            doc.fillColor("#000").font(this.boldFont).fontSize(9);
            doc.text("Фото", colImg, currentY + 5);
            doc.text(t("pdf_table_product", "ru"), colX[0], currentY + 5);
            doc.text(t("pdf_table_details", "ru"), colX[1], currentY + 5);
            doc.text(t("dept_label", "ru"), colX[2], currentY + 5);
            doc.text(t("worker_label", "ru"), colX[3], currentY + 5);
            currentY += 20;
          }

          doc.rect(30, currentY, 535, rowHeight).stroke("#eee");

          const buffer = await this.ensureImageBuffer(item);
          if (buffer) {
            try {
              doc.image(buffer, colImg - 2, currentY + 5, {
                fit: [55, 60],
              });
            } catch (e) {
              logger.warn({ err: e }, "PDF image embed failed");
            }
          }

          doc
            .font(this.boldFont)
            .fontSize(9)
            .fillColor("#000")
            .text(`${index + 1}. ${item.product}`, colX[0], currentY + 10, {
              width: 110,
            });
          doc
            .font(this.defaultFont)
            .fontSize(8)
            .text(item.details || "-", colX[1], currentY + 5, { width: 135 });

          doc.text(`${item.department}`, colX[2], currentY + 10, {
            width: 85,
          });

          const worker =
            item.assignedWorker || t("dist_not_assigned", "ru").toUpperCase();
          doc
            .font(this.boldFont)
            .fillColor(item.assignedWorker ? "#1a73e8" : "#d93025")
            .text(worker, colX[3], currentY + 15, { width: 120 });
          doc.fillColor("#000");

          currentY += rowHeight;
        }
      };

      processRows()
        .then(() => {
          // --- FOOTER ---
          doc
            .fontSize(8)
            .fillColor("#999")
            .text(t("pdf_footer", "ru"), 30, 780, {
              align: "center",
              width: 535,
            });

          doc.end();
        })
        .catch(reject);
    });
  }

  // ─── Fabric Order PDF ───────────────────────────────────────────────────────

  /**
   * Generates a Fabric Order PDF listing items with fabric requirements.
   */
  async generateFabricOrderPDF(order: OrderDetail): Promise<Buffer> {
    const fabricItems = order.items.filter(
      (i) =>
        i.fabricDetails ||
        (i.details && i.details.toLowerCase().includes("kumaş")),
    );

    return new Promise((resolve, reject) => {
      const doc = new PDFDocument({ margin: 30, size: "A4" });
      const chunks: Buffer[] = [];
      doc.on("data", (chunk: Buffer) => chunks.push(chunk));
      doc.on("end", () => resolve(Buffer.concat(chunks)));
      doc.on("error", (err: Error) => reject(err));

      // HEADER
      doc.rect(30, 30, 535, 50).fill("#5d4037");
      doc
        .font(this.boldFont)
        .fontSize(16)
        .fillColor("#ffffff")
        .text("ЗАКАЗ ТКАНИ", 30, 45, {
          align: "center",
          width: 535,
        });

      let currentY = 100;
      doc
        .fillColor("#000")
        .font(this.boldFont)
        .fontSize(11)
        .text(`${t("customer_label", "ru")}: `, 30, currentY, {
          continued: true,
        })
        .font(this.defaultFont)
        .text(order.customerName);

      doc
        .font(this.boldFont)
        .text(`№ Заказа: `, 30, currentY + 15, {
          continued: true,
        })
        .font(this.defaultFont)
        .text(order.orderNumber);

      currentY += 50;

      const processFabricItems = async () => {
        for (let index = 0; index < fabricItems.length; index++) {
          const item = fabricItems[index];
          if (currentY > 700) {
            doc.addPage();
            currentY = 40;
          }

          doc.rect(30, currentY, 535, 100).stroke("#ccc");

          const buffer = await this.ensureImageBuffer(item);
          if (buffer) {
            try {
              doc.image(buffer, 40, currentY + 10, { fit: [80, 80] });
            } catch (_e) {
              // Silently skip image if it cannot be embedded
            }
          }

          doc
            .fillColor("#000")
            .font(this.boldFont)
            .fontSize(10)
            .text(`${index + 1}. ${item.product}`, 130, currentY + 15);

          const fabric = item.fabricDetails;
          if (fabric) {
            doc
              .font(this.boldFont)
              .text(`Ткань: `, 130, currentY + 35, { continued: true })
              .font(this.defaultFont)
              .text(fabric.name || "-");
            doc
              .font(this.boldFont)
              .text(`Количество: `, 130, currentY + 50, {
                continued: true,
              })
              .font(this.defaultFont)
              .text(`${(fabric.amount * (item.quantity || 1)).toFixed(1)} m`);
          } else {
            doc
              .font(this.defaultFont)
              .text(item.details || "-", 130, currentY + 35, { width: 400 });
          }

          currentY += 110;
        }
      };

      processFabricItems()
        .then(() => {
          doc
            .fontSize(8)
            .fillColor("#999")
            .text(t("pdf_footer", "ru"), 30, 780, {
              align: "center",
              width: 535,
            });
          doc.end();
        })
        .catch(reject);
    });
  }

  // ─── PDF → Image Conversion ─────────────────────────────────────────────────

  /**
   * Renders the first page of a PDF buffer to a PNG Buffer.
   * Uses pdfjs-dist + canvas for rendering.
   */
  async generatePDFView(pdfBuffer: Buffer): Promise<Buffer> {
    try {
      logger.info("PDF Görünümü (PNG) oluşturuluyor...");

      const uint8Array = new Uint8Array(pdfBuffer);
      const nodeModulesPath = path.join(
        process.cwd(),
        "node_modules",
        "pdfjs-dist",
      );
      const cMapUrl =
        pathToFileURL(path.join(nodeModulesPath, "cmaps")).href + "/";
      const standardFontDataUrl =
        pathToFileURL(path.join(nodeModulesPath, "standard_fonts")).href + "/";

      const loadingTask = pdfjsLib.getDocument({
        data: uint8Array,
        useSystemFonts: true,
        disableFontFace: false,
        cMapUrl,
        cMapPacked: true,
        standardFontDataUrl,
        isEvalSupported: false,
      });

      const pdfDocument = await loadingTask.promise;
      const page = await pdfDocument.getPage(1);

      const scale = 3.0;

      // Register fonts for canvas rendering
      const regularPath = this.fontRegular;
      const boldPath = this.fontBold;
      if (fs.existsSync(regularPath))
        registerFont(regularPath, { family: "Roboto" });
      if (fs.existsSync(boldPath))
        registerFont(boldPath, { family: "Roboto", weight: "bold" });

      const viewport = page.getViewport({ scale });
      const canvas = createCanvas(viewport.width, viewport.height);
      const context = canvas.getContext("2d");

      context.fillStyle = "white";
      context.fillRect(0, 0, canvas.width, canvas.height);

      await page.render({ canvasContext: context, viewport }).promise;

      logger.info("PDF başarıyla PNG'ye dönüştürüldü (Scale: 3.0).");
      return canvas.toBuffer("image/png");
    } catch (error) {
      logger.error({ err: error }, "PDF → PNG dönüşüm hatası");
      throw error;
    }
  }

  // ─── Archive Helpers ────────────────────────────────────────────────────────

  /**
   * Saves a PDF buffer to the daily archive folder.
   */
  async archivePDF(deptName: string, pdfBuffer: Buffer): Promise<string> {
    const today = new Date().toISOString().split("T")[0];
    const pdfDir = path.join(process.cwd(), "data", "orders", today, "pdfs");

    if (!fs.existsSync(pdfDir)) {
      fs.mkdirSync(pdfDir, { recursive: true });
    }

    const safeName = deptName.replace(/[^a-z0-9]/gi, "_").toUpperCase();
    const fileName = `is_emri_${safeName}_${Date.now()}.pdf`;
    const filePath = path.join(pdfDir, fileName);

    fs.writeFileSync(filePath, pdfBuffer);
    logger.info(`PDF arşivlendi: ${filePath}`);
    return filePath;
  }

  // ─── Job Order PDF ──────────────────────────────────────────────────────────

  /**
   * Generates a department-specific Job Order PDF.
   * Contains product images, quantities, and details in Russian.
   */
  async generateJobOrderPDF(
    items: OrderItem[],
    customerName: string,
    department: string,
  ): Promise<Buffer> {
    return new Promise((resolve, reject) => {
      try {
        const doc = new PDFDocument({ margin: 30, size: "A4" });
        const chunks: Buffer[] = [];

        doc.on("data", (chunk: Buffer) => chunks.push(chunk));
        doc.on("end", () => resolve(Buffer.concat(chunks)));
        doc.on("error", (err: Error) => reject(err));

        // --- HEADER ---
        doc.rect(30, 30, 535, 50).fill("#1a1a1a");
        const translatedDept = translateDepartment(department, "ru");
        doc
          .font(this.boldFont)
          .fontSize(16)
          .fillColor("#ffffff")
          .text(translatedDept.toUpperCase(), 30, 45, {
            align: "center",
            width: 535,
          });

        doc.moveDown(2);
        let currentY = 100;

        // --- CUSTOMER INFO ---
        doc
          .fillColor("#000")
          .font(this.boldFont)
          .fontSize(12)
          .text(`${t("customer_label", "ru")}: `, 30, currentY, {
            continued: true,
          });
        doc.font(this.defaultFont).text(customerName);

        doc
          .font(this.boldFont)
          .text(`${t("pdf_date", "ru")}: `, 30, currentY + 15, {
            continued: true,
          });
        doc.font(this.defaultFont).text(new Date().toLocaleDateString("tr-TR"));

        currentY += 45;

        // --- ITEMS ---
        const processItems = async () => {
          for (let index = 0; index < items.length; index++) {
            const item = items[index];
            if (currentY > 600) {
              doc.addPage();
              currentY = 40;
            }

            doc.rect(30, currentY, 535, 150).stroke("#cccccc");

            const buffer = await this.ensureImageBuffer(item);
            if (buffer) {
              try {
                doc.image(buffer, 40, currentY + 15, {
                  fit: [120, 120],
                  align: "center",
                  valign: "center",
                });
              } catch {
                doc
                  .fontSize(8)
                  .fillColor("#999")
                  .text(t("pdf_no_image_error", "ru"), 40, currentY + 60);
              }
            } else {
              doc.rect(40, currentY + 15, 120, 120).stroke("#eee");
              doc
                .fontSize(8)
                .fillColor("#999")
                .text(t("pdf_no_image", "ru"), 65, currentY + 65);
            }

            doc.fillColor("#000").font(this.boldFont).fontSize(11);
            doc.text(`${index + 1}. ${item.product}`, 180, currentY + 20);

            doc.font(this.boldFont).fontSize(10);
            doc.text(`${t("pdf_table_quantity", "ru")}:`, 180, currentY + 45, {
              continued: true,
            });
            doc.font(this.defaultFont).text(` ${item.quantity}`);

            doc
              .font(this.boldFont)
              .text(`${t("details_label", "ru")}:`, 180, currentY + 65);
            doc
              .font(this.defaultFont)
              .fontSize(9)
              .text(item.details || "-", 180, currentY + 80, { width: 360 });

            if (item.assignedWorker) {
              doc
                .font(this.boldFont)
                .text(`${t("worker_label", "ru")}:`, 180, currentY + 120, {
                  continued: true,
                });
              doc.font(this.defaultFont).text(` ${item.assignedWorker}`);
            }

            currentY += 165;
          }
        };

        processItems()
          .then(() => {
            // --- FOOTER ---
            doc
              .fontSize(7)
              .fillColor("#aaa")
              .text(t("pdf_footer", "ru"), 30, 790, {
                align: "center",
                width: 535,
              });

            doc.end();
          })
          .catch(reject);
      } catch (e) {
        reject(e);
      }
    });
  }
}

import { createClient } from "@supabase/supabase-js";
import { ImapFlow } from "imapflow";
import OpenAI from "openai";
import pino from "pino";
import dotenv from "dotenv";

dotenv.config();
const logger = pino({ name: "DoctorService" });

export interface DiagnosticResult {
  service: string;
  status: "OK" | "ERROR" | "WARNING";
  message: string;
  remedy?: string;
}

export class DoctorService {
  private supabaseUrl: string;
  private supabaseKey: string;
  private openai: OpenAI;

  constructor() {
    // SSL/TLS verification enabled by default

    this.supabaseUrl = process.env.SUPABASE_URL || "";
    this.supabaseKey = process.env.SUPABASE_KEY || "";
    this.openai = new OpenAI({
      apiKey: process.env.OPENROUTER_API_KEY,
      baseURL: "https://openrouter.ai/api/v1",
    });
  }

  public async checkVectorMemory(): Promise<DiagnosticResult> {
    if (!this.supabaseUrl || !this.supabaseKey) {
      return {
        service: "Vector Memory (pgvector)",
        status: "WARNING",
        message: "Supabase kimlik bilgileri eksik, vektör kontrolü yapılamadı.",
      };
    }
    const supabase = createClient(this.supabaseUrl, this.supabaseKey);
    try {
      const { error } = await supabase
        .from("visual_memory")
        .select("id")
        .limit(1);
      if (error) {
        if (error.message.includes("does not exist")) {
          return {
            service: "Vector Memory (pgvector)",
            status: "ERROR",
            message: "Hata: visual_memory tablosu bulunamadı.",
            remedy:
              "Supabase SQL Editor üzerinden visual_memory tablosunu oluşturun.",
          };
        }
        throw error;
      }
      return {
        service: "Vector Memory (pgvector)",
        status: "OK",
        message: "Bağlantı başarılı ve pgvector tablosu aktif.",
      };
    } catch (error: any) {
      return {
        service: "Vector Memory (pgvector)",
        status: "ERROR",
        message: `Hata: ${error.message}`,
        remedy: "Supabase ve pgvector eklentisi ayarlarını kontrol edin.",
      };
    }
  }

  public async checkSupabase(): Promise<DiagnosticResult> {
    if (!this.supabaseUrl || !this.supabaseKey) {
      return {
        service: "Supabase",
        status: "WARNING",
        message: "Kimlik bilgileri eksik.",
      };
    }
    const supabase = createClient(this.supabaseUrl, this.supabaseKey);
    try {
      const { error } = await supabase.from("orders").select("id").limit(1);
      if (error) throw error;
      return {
        service: "Supabase",
        status: "OK",
        message: `Bağlantı OK. Proje: ${this.supabaseUrl.split("//")[1].split(".")[0]}`,
      };
    } catch (error: any) {
      return {
        service: "Supabase",
        status: "ERROR",
        message: `Sorgu hatası: ${error.message}`,
        remedy: "Supabase ayarlarını kontrol edin.",
      };
    }
  }

  public async checkLLM(): Promise<DiagnosticResult> {
    try {
      await this.openai.chat.completions.create({
        model: process.env.OPENROUTER_MODEL || "google/gemini-2.0-flash",
        messages: [{ role: "user", content: "ping" }],
        max_tokens: 5,
      });
      return {
        service: "LLM (OpenRouter)",
        status: "OK",
        message: "Bağlantı başarılı.",
      };
    } catch (error: any) {
      return {
        service: "LLM (OpenRouter)",
        status: "ERROR",
        message: error.message,
      };
    }
  }

  public async checkGmail(): Promise<DiagnosticResult> {
    const client = new ImapFlow({
      host: "imap.gmail.com",
      port: 993,
      secure: true,
      auth: {
        user: process.env.GMAIL_USER || "",
        pass: process.env.GMAIL_PASS || "",
      },
      tls: { rejectUnauthorized: true },
    });
    try {
      await client.connect();
      await client.logout();
      return {
        service: "Gmail (IMAP)",
        status: "OK",
        message: "Giriş başarılı.",
      };
    } catch (error: any) {
      return {
        service: "Gmail (IMAP)",
        status: "ERROR",
        message: error.message,
      };
    }
  }

  /**
   * TCP socket ile portu test eder — HTTP'ye gerek yok, salt bağlantı kontrolü.
   */
  private testTcpPort(
    host: string,
    port: number,
    timeoutMs = 5000,
  ): Promise<number> {
    return new Promise((resolve, reject) => {
      const net = require("net");
      const start = Date.now();
      const socket = new net.Socket();
      socket.setTimeout(timeoutMs);
      socket.connect(port, host, () => {
        const elapsed = Date.now() - start;
        socket.destroy();
        resolve(elapsed);
      });
      socket.on("error", (err: Error) => {
        socket.destroy();
        reject(err);
      });
      socket.on("timeout", () => {
        socket.destroy();
        reject(new Error("Timeout"));
      });
    });
  }

  public async checkNetwork(): Promise<DiagnosticResult> {
    const LATENCY_THRESHOLD = 300;
    // Kritik mail portları — sistem bunlar olmadan çalışmaz
    const mailTargets = [
      { host: "smtp.gmail.com", port: 587, label: "Gmail SMTP" },
      { host: "imap.gmail.com", port: 993, label: "Gmail IMAP" },
    ];

    // Altyapı ve Genel İnternet kontrolleri
    const infraTargets = [
      {
        host: "aejhzxvuegchakaknwts.supabase.co",
        port: 443,
        label: "Supabase",
      },
      { host: "google.com", port: 443, label: "Google (Internet)" },
    ];

    let report = "Ağ Tarama Sonuçları:\n";
    let hasNetworkError = false;

    // Mail Port Kontrolleri (TCP)
    for (const target of mailTargets) {
      try {
        const elapsed = await this.testTcpPort(target.host, target.port);
        const warning = elapsed > LATENCY_THRESHOLD ? " ⚠️ Yüksek gecikme" : "";
        report += `✅ ${target.label} -> ERİŞİLEBİLİR (${elapsed}ms)${warning}\n`;
      } catch (e: any) {
        hasNetworkError = true;
        report += `❌ ${target.label} -> HATA: ${e.message}\n`;
      }
    }

    // Altyapı Kontrolleri (HTTPS fetch)
    for (const target of infraTargets) {
      const start = Date.now();
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 5000);
        const protocol = "https";

        await fetch(`${protocol}://${target.host}`, {
          method: "HEAD",
          signal: controller.signal,
          // @ts-ignore
          agent: new (require("https").Agent)({ rejectUnauthorized: true }),
        }).catch((fetchErr: any) => {
          // Re-throw only real network errors; HTTP-level errors (4xx, 3xx) mean server is reachable
          const isNetworkError =
            fetchErr.name === "AbortError" ||
            fetchErr.message?.includes("ENOTFOUND") ||
            fetchErr.message?.includes("ECONNREFUSED") ||
            fetchErr.message?.includes("ETIMEDOUT");
          if (isNetworkError) throw fetchErr;
          // Otherwise swallow — server answered even if with an error code
        });

        clearTimeout(timeoutId);
        const elapsed = Date.now() - start;
        const warning = elapsed > LATENCY_THRESHOLD ? " ⚠️ Yüksek gecikme" : "";
        report += `✅ ${target.label} -> ERİŞİLEBİLİR (${elapsed}ms)${warning}\n`;
      } catch (e: any) {
        hasNetworkError = true;
        const msg = e.name === "AbortError" ? "Timeout (5s)" : e.message;
        report += `❌ ${target.label} -> HATA: ${msg}\n`;
      }
    }

    return {
      service: "Network Scanner",
      status: hasNetworkError ? "WARNING" : "OK",
      message: report,
    };
  }

  public async runFullDiagnostics(): Promise<DiagnosticResult[]> {
    return [
      await this.checkVectorMemory(),
      await this.checkNetwork(),
      await this.checkSupabase(),
      await this.checkLLM(),
      await this.checkGmail(),
    ];
  }

  public async checkSystem(): Promise<string> {
    const results = await this.runFullDiagnostics();
    return this.formatReport(results);
  }

  public formatReport(results: DiagnosticResult[]): string {
    const escape = (str: string) =>
      str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
    let report = "<b>🩺 SİSTEM SAĞLIK RAPORU (DOCTOR)</b>\n\n";
    results.forEach((res) => {
      const icon =
        res.status === "OK" ? "✅" : res.status === "WARNING" ? "⚠️" : "❌";
      report += `${icon} <b>${escape(res.service)}</b>: ${res.status}\n`;
      report += `📝 <i>${escape(res.message)}</i>\n`;
      if (res.remedy) report += `💡 <b>Çözüm:</b> ${escape(res.remedy)}\n`;
      report += "┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈┈\n";
    });
    const errors = results.filter((r) => r.status === "ERROR").length;
    report +=
      errors === 0
        ? "\n🚀 <b>Sistem stabil.</b>"
        : `\n⚠️ <b>${errors} hata bulundu.</b>`;
    return report;
  }
}

import * as ExcelJS from "exceljs";
import * as fs from "fs";
import * as path from "path";
import * as os from "os";
import crypto from "crypto";
import { OrderDetail, OrderItem } from "../models/order.schema";
import { pino } from "pino";

const logger = pino();

/**
 * Sabit sipariş formu için deterministik Excel parser.
 *
 * Form yapısı (sabit):
 *  - Satır 2: MUSTERI ADI       → B2
 *  - Satır 3: SIPARIS TARIHI    → B3
 *  - Satır 7: SİPARİŞ NO        → B7
 *  - Satır 8: Başlık satırı
 *  - Satır 9+: Ürün satırları
 *
 * Sütun haritası (satır 8 başlıkları):
 *  A(1)=Resim  B(2)=Kod  C(3)=Ürün Adı  D(4)=Miktar  E(5)=Ölçü
 *  F(6)=Departman  G(7)=Stok/Not  H(8)=Tür(AHSAP/PLASTİK/METAL)
 *  I(9)=Kumaş  J(10)=Dikiş  K(11)=Döşeme  L(12)=Kumaş mt
 *  M(13)=Boya  N(14)=İp  O(15)=İp mt  P(16)=Not  S(19)=Teslim
 */

const COL = {
  RESIM: 1,
  KOD: 2,
  URUN_ADI: 3,
  MIKTAR: 4,
  OLCU: 5,
  DEPARTMAN: 6,
  STOK_NOT: 7,
  TUR: 8,        // AHSAP / PLASTİK / METAL
  KUMAS: 9,
  DIKIS: 10,
  DOSEME: 11,
  KUMAS_MT: 12,
  BOYA: 13,
  IP: 14,
  IP_MT: 15,
  NOT: 16,
  TESLIM: 19,
};

const HEADER_ROW = 8;
const DATA_START_ROW = 9;

function cellVal(row: ExcelJS.Row, col: number): string {
  const cell = row.getCell(col);
  return (cell.text || String(cell.value ?? "")).trim();
}

function isEmpty(v: string): boolean {
  return !v || v.toLowerCase() === "yok" || v === "-" || v === "0";
}

function isPlastic(tur: string, urunAdi: string, not: string): boolean {
  const keywords = [
    "plastik", "пластик", "plastic", "полимер", "полипропилен",
    "пластиковый", "пластиковые", "пластмасс", "пвх", "pvc", "pp",
  ];
  const haystack = `${tur} ${urunAdi} ${not}`.toLowerCase();
  return keywords.some((kw) => haystack.includes(kw));
}

export interface ParsedOrderResult {
  order: OrderDetail;
  imageMap: Map<number, { buffer: Buffer; extension: string }>;
}

export async function parseOrderExcel(
  bufferOrPath: Buffer | string,
): Promise<ParsedOrderResult | null> {
  const wb = new ExcelJS.Workbook();
  let tempFile: string | null = null;

  try {
    if (typeof bufferOrPath === "string") {
      await wb.xlsx.readFile(bufferOrPath);
    } else {
      tempFile = path.join(
        os.tmpdir(),
        `order_${crypto.randomBytes(6).toString("hex")}.xlsx`,
      );
      fs.writeFileSync(tempFile, bufferOrPath);
      await wb.xlsx.readFile(tempFile);
    }
  } catch (e) {
    logger.error({ err: e }, "Excel okunamadı");
    return null;
  } finally {
    if (tempFile && fs.existsSync(tempFile)) fs.unlinkSync(tempFile);
  }

  const ws = wb.getWorksheet(1);
  if (!ws) {
    logger.error("Worksheet bulunamadı");
    return null;
  }

  // ── Form bilgileri ──────────────────────────────────────────────
  const musteriAdi = cellVal(ws.getRow(2), 2) || "Bilinmiyor";
  const siparisTarihi = cellVal(ws.getRow(3), 2);
  const siparisNo = cellVal(ws.getRow(7), 2) || `SD-${Date.now()}`;
  const teslimTarihi = (() => {
    // İlk ürün satırından teslim tarihi al (S sütunu)
    for (let r = DATA_START_ROW; r <= ws.rowCount; r++) {
      const v = cellVal(ws.getRow(r), COL.TESLIM);
      if (v && v !== "") return v;
    }
    return siparisTarihi || "Belirtilmemiş";
  })();

  logger.info(
    { musteriAdi, siparisNo },
    "📋 Sipariş formu ayrıştırılıyor (sabit parser)",
  );

  // ── Resimleri oku ───────────────────────────────────────────────
  const imageMap = new Map<number, { buffer: Buffer; extension: string }>();
  const wsImages = ws.getImages();

  wsImages.forEach((img) => {
    const excelImg = wb.getImage(Number(img.imageId));
    if (!excelImg?.buffer) return;
    const startRow = Math.floor(img.range.tl.row) + 1; // 0-indexed → 1-indexed
    const buf = Buffer.from(excelImg.buffer as any);
    const ext = excelImg.extension || "png";
    if (!imageMap.has(startRow)) {
      imageMap.set(startRow, { buffer: buf, extension: ext });
    }
  });

  logger.info(`🖼️ ${imageMap.size} resim Excel'den okundu`);

  // ── Ürün satırlarını işle ───────────────────────────────────────
  const orderId = Date.now().toString();
  const items: OrderItem[] = [];
  let itemIndex = 0;

  for (let rowNum = DATA_START_ROW; rowNum <= ws.rowCount; rowNum++) {
    const row = ws.getRow(rowNum);

    const urunAdi = cellVal(row, COL.URUN_ADI);
    if (!urunAdi) continue; // Boş satır, atla

    const kod = cellVal(row, COL.KOD);
    const miktar = parseInt(cellVal(row, COL.MIKTAR)) || 0;
    const olcu = cellVal(row, COL.OLCU);
    const departmanHam = cellVal(row, COL.DEPARTMAN);
    const stokNot = cellVal(row, COL.STOK_NOT);
    const tur = cellVal(row, COL.TUR);
    const kumas = cellVal(row, COL.KUMAS);
    const dikis = cellVal(row, COL.DIKIS);
    const doseme = cellVal(row, COL.DOSEME);
    const kumasMt = parseFloat(cellVal(row, COL.KUMAS_MT)) || 0;
    const boya = cellVal(row, COL.BOYA);
    const ip = cellVal(row, COL.IP);
    const not = cellVal(row, COL.NOT);

    const imgData = imageMap.get(rowNum);

    // ── Plastik kontrolü ──────────────────────────────────────────
    if (isPlastic(tur, urunAdi, stokNot)) {
      items.push(makeItem(
        orderId, itemIndex++, rowNum,
        urunAdi, kod, "Satınalma", miktar, olcu,
        (() => {
          // stokNot/not içindeki alım/satın alma eşanlamlılarını filtrele
          const ALIM_KEYWORDS = ["dış alım", "satın alma", "satınalma", "external", "закупка", "alım"];
          const extra = (not || stokNot || "").trim();
          const isRedundant = ALIM_KEYWORDS.some(k => extra.toLowerCase().includes(k));
          return isRedundant || !extra ? "Внешняя закупка (пластик)." : `Внешняя закупка (пластик). ${extra}`;
        })(),
        undefined, undefined,
        imgData?.buffer, imgData?.extension,
      ));
      logger.info(`🛒 Plastik ürün → Satınalma: ${urunAdi}`);
      continue;
    }

    // ── Karkas / ana departman ────────────────────────────────────
    const karkasFlag =
      departmanHam.toLowerCase().includes("karkas") ||
      stokNot.toLowerCase().includes("karkas") ||
      stokNot.toLowerCase().includes("üretim yapılacak") ||
      stokNot.toLowerCase().includes("üretilecek");

    if (karkasFlag) {
      const detay = [
        boya ? `Цвет: ${boya}` : "",
        stokNot || "",
        not || "",
        olcu ? `Размер: ${olcu}` : "",
      ].filter(Boolean).join(" | ");

      items.push(makeItem(
        orderId, itemIndex++, rowNum,
        urunAdi, kod, "Karkas Üretimi", miktar, olcu,
        detay,
        undefined,
        boya ? { name: boya } : undefined,
        imgData?.buffer, imgData?.extension,
      ));
      logger.info(`🔩 Karkas: ${urunAdi}`);
    }

    // ── Boyahane ──────────────────────────────────────────────────
    if (!isEmpty(boya)) {
      items.push(makeItem(
        orderId, itemIndex++, rowNum,
        urunAdi, kod, "Boyahane", miktar, olcu,
        `Цвет: ${boya}`,
        undefined,
        { name: boya },
        imgData?.buffer, imgData?.extension,
      ));
      logger.info(`🎨 Boyahane: ${urunAdi} → ${boya}`);
    }

    // ── Kumaş (Marina için) ───────────────────────────────────────
    if (!isEmpty(kumas)) {
      const kumasMiktar = kumasMt > 0 ? kumasMt * miktar : 0;
      items.push(makeItem(
        orderId, itemIndex++, rowNum,
        urunAdi, kod, "Kumaş", miktar, olcu,
        `Ткань: ${kumas}${kumasMiktar > 0 ? ` | Итого: ${kumasMiktar} м` : ""}`,
        { name: kumas, amount: kumasMiktar },
        undefined,
        imgData?.buffer, imgData?.extension,
      ));
      logger.info(`🧶 Kumaş: ${urunAdi} → ${kumas}`);
    }

    // ── Dikişhane ─────────────────────────────────────────────────
    // Kural: dikis sütunu doluysa veya kumaş + dikis birlikte varsa tetiklenir
    if (!isEmpty(dikis)) {
      items.push(makeItem(
        orderId, itemIndex++, rowNum,
        urunAdi, kod, "Dikişhane", miktar, olcu,
        `Шитьё: ${dikis}${ip ? ` | Нить: ${ip}` : ""}`,
        !isEmpty(kumas) ? { name: kumas, amount: kumasMt * miktar } : undefined,
        undefined,
        imgData?.buffer, imgData?.extension,
      ));
      logger.info(`🧵 Dikişhane: ${urunAdi}`);
    }

    // ── Döşemehane ────────────────────────────────────────────────
    // Kural: kumaş varsa döşemehane KESİNLİKLE tetiklenir (doseme sütunu boş olsa bile)
    if (!isEmpty(doseme) || !isEmpty(kumas)) {
      items.push(makeItem(
        orderId, itemIndex++, rowNum,
        urunAdi, kod, "Döşemehane", miktar, olcu,
        `Обивка: ${doseme || kumas}${!isEmpty(kumas) ? ` | Ткань: ${kumas}` : ""}`,
        !isEmpty(kumas) ? { name: kumas, amount: kumasMt * miktar } : undefined,
        undefined,
        imgData?.buffer, imgData?.extension,
      ));
      logger.info(`🪑 Döşemehane: ${urunAdi}`);
    }

    // ── Hiçbir kural tetiklenmediyse genel departmana at ─────────
    if (!karkasFlag && isEmpty(boya) && isEmpty(kumas) && isEmpty(dikis) && isEmpty(doseme)) {
      const dept = departmanHam || "Karkas Üretimi";
      items.push(makeItem(
        orderId, itemIndex++, rowNum,
        urunAdi, kod, dept, miktar, olcu,
        [stokNot, not].filter(Boolean).join(" | "),
        undefined, undefined,
        imgData?.buffer, imgData?.extension,
      ));
      logger.info(`📦 Genel dept (${dept}): ${urunAdi}`);
    }
  }

  if (items.length === 0) {
    logger.warn("Excel'den hiç ürün ayrıştırılamadı");
    return null;
  }

  const order: OrderDetail = {
    id: orderId,
    orderNumber: siparisNo,
    customerName: musteriAdi,
    deliveryDate: teslimTarihi,
    items,
    status: "new",
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };

  logger.info(
    { itemCount: items.length, depts: [...new Set(items.map((i) => i.department))] },
    "✅ Sabit parser tamamlandı",
  );

  return { order, imageMap };
}

// ── Yardımcı: OrderItem oluştur ────────────────────────────────────
function makeItem(
  orderId: string,
  index: number,
  rowIndex: number,
  urunAdi: string,
  kod: string,
  department: string,
  quantity: number,
  olcu: string,
  details: string,
  fabricDetails?: { name: string; amount: number },
  paintDetails?: { name: string },
  imageBuffer?: Buffer,
  imageExtension?: string,
): OrderItem {
  return {
    id: `${orderId}_${index}`,
    product: urunAdi + (kod ? ` (${kod})` : ""),
    department,
    quantity,
    details: [details, olcu ? `Размер: ${olcu}` : ""].filter(Boolean).join(" | "),
    source: department === "Satınalma" ? "External" : "Production",
    status: "bekliyor",
    rowIndex,
    fabricDetails: fabricDetails
      ? { ...fabricDetails, arrived: false }
      : undefined,
    paintDetails,
    imageBuffer,
    imageExtension,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}

import * as fs from "fs";
import * as path from "path";
import { OpenRouterService } from "./llm.service";
import { StaffService } from "./staff.service";
import { ExcelRow } from "./xlsx-utils";
import { ImageEmbeddingService } from "./image-embedding.service";
import { SupabaseService } from "./supabase.service";
import { t, Language, translateDepartment } from "./i18n";
import { pino } from "pino";
import { OrderRepository } from "../repositories/order.repository";
import { PDFService } from "../services/pdf.service";
import { OrderDetail, OrderItem } from "../models/order.schema";
import { parseOrderExcel } from "./excel-order-parser";

const logger = pino();

// Re-export types from central schema for backward compatibility
export type { OrderItem, OrderDetail } from "../models/order.schema";
export class OrderService {
  private repository: OrderRepository;
  private pdfService: PDFService;
  private llmService: OpenRouterService;
  private staffService: StaffService;
  private imageEmbeddingService: ImageEmbeddingService;
  private supabase: SupabaseService;

  private static instance: OrderService;

  private constructor() {
    this.repository = OrderRepository.getInstance();
    this.pdfService = PDFService.getInstance();
    this.llmService = new OpenRouterService();
    this.staffService = StaffService.getInstance();
    this.imageEmbeddingService = new ImageEmbeddingService();
    this.supabase = SupabaseService.getInstance();
    this.repository.loadOrders(); // Başlangıçta asenkron yükleme başlar
  }

  public static getInstance(): OrderService {
    if (!OrderService.instance) {
      OrderService.instance = new OrderService();
    }
    return OrderService.instance;
  }

  /** @deprecated Use repository.loadOrders() instead. Kept for backward compatibility. */
  public async loadOrdersFromSupabase(): Promise<void> {
    await this.repository.loadOrders();
  }

  // Departman ismini i18n üzerinden çevirir (varsayılan: ru)
  public getDeptTranslation(dept: string, lang: Language = "ru"): string {
    return translateDepartment(dept, lang);
  }

  /**
   * Email veya Excel içeriğini analiz eder.
   */
  async parseAndCreateOrder(
    subject: string,
    content: string,
    uid: string,
    attachments?: any[],
  ): Promise<OrderDetail | null> {
    try {
      // 🚨 SİSTEM VE REKLAM MAİLLERİNİ FİLTRELE
      const lowerSubject = (subject || "").toLowerCase();
      const lowerContent = (content || "").toLowerCase();
      const hasExcel = attachments?.some(a => a.filename?.endsWith(".xlsx") || a.filename?.endsWith(".xls"));

      // Eğer mail bir sipariş içermiyorsa (Excel yoksa) ve sistem/bildirim maili gibiyse atla
      const isSystemMail = 
        lowerSubject.includes("netlify") || 
        lowerSubject.includes("welcome") ||
        lowerSubject.includes("verification") ||
        lowerSubject.includes("security alert") ||
        lowerSubject.includes("deploy") ||
        lowerSubject.includes("netlify team") ||
        lowerContent.includes("netlify") ||
        lowerContent.includes("team is ready") ||
        lowerContent.includes("deploy your first app") ||
        lowerContent.includes("subscription") ||
        lowerContent.includes("billing");

      if (isSystemMail && !hasExcel) {
        console.log(`⏭️ [SKIP] Sistem maili tespit edildi, sipariş işlemi atlanıyor: "${subject}"`);
        return null;
      }

      let fullContent = `Konu: ${subject}\n\nİçerik:\n${content}`;
      let isExcel = false;
      let rawExcelData: ExcelRow[] | undefined;

      // ── EXCEL EKİ: Sabit parser ile işle (LLM gerekmez) ──────────
      if (attachments && attachments.length > 0) {
        for (const attachment of attachments) {
          const isXlsx =
            attachment.contentType ===
              "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" ||
            attachment.filename?.endsWith(".xlsx") ||
            attachment.filename?.endsWith(".xls");

          if (!isXlsx) continue;

          try {
            logger.info(`📊 Sabit Excel parser başlatılıyor: ${attachment.filename}`);
            const parsed = await parseOrderExcel(attachment.content);

            if (!parsed) {
              logger.warn(`⚠️ Sabit parser sonuç döndürmedi: ${attachment.filename}`);
              continue;
            }

            const { order: excelOrder } = parsed;

            // Mükerrer kontrolü
            const allOrders = this.repository.getAll();
            const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
            const recentOrders = allOrders.filter((o: OrderDetail) => o.createdAt > oneDayAgo);

            for (const existing of recentOrders) {
              if (
                excelOrder.orderNumber &&
                existing.orderNumber === excelOrder.orderNumber
              ) {
                logger.warn(`⚠️ Mükerrer sipariş (no eşleşti): ${excelOrder.orderNumber}`);
                return { ...existing, isDuplicate: true };
              }
            }

            excelOrder.createdAt = new Date().toISOString();
            excelOrder.updatedAt = new Date().toISOString();

            await this.repository.save(excelOrder);

            try { await this.saveToVisualMemory(excelOrder); } catch (_) {}
            await this.logOrder(excelOrder);

            logger.info(
              { orderNumber: excelOrder.orderNumber, items: excelOrder.items.length },
              "✅ Sabit Excel parser ile sipariş oluşturuldu",
            );
            return excelOrder;

          } catch (err) {
            logger.error({ err }, `❌ Sabit Excel parser hatası: ${attachment.filename}`);
          }
        }
      }

      const prompt = `
      Sen profesyonel bir Sandaluci Üretim Planlama Asistanısın. Görevin, gelen veriyi (EXCEL tablosu veya E-POSTA gövdesi) analiz ederek departmanlara göre hatasız parçalamak ve ÇİFT DİLLİ (Türkçe ve Rusça) sipariş verisi oluşturmaktır.

      🚨 ÖNEMLİ: Girdi bir E-POSTA metniyse (özellikle "Fwd:" ile başlayan forwarded mailler), mailin alt kısımlarındaki asıl sipariş detaylarını bul ve odaklan.
      E-postanın en üstündeki yönlendirme bilgilerini (From, Date, Subject) geçerek, asıl mesaj gövdesindeki sipariş kalemlerini (Ürün, Adet, Kumaş, Boya vb.) tespit et.

      🚨 DİL KURALI:
      - Çalışanlar Rusça, patron (Barış Bey) Türkçe bilmektedir.
      - "product" ve "details" alanlarını HER ZAMAN "[TR] ... / [RU] ..." formatında doldur.
      - Örn: "product": "[TR] 274 Sandalye / [RU] 274 Стул"
      - Örn: "details": "[TR] Kumaş: Dorian 12 / [RU] Ткань: Dorian 12"

      DEPARTMAN ATAMA KURALLARI (KESİNLİKLE UYMAK ZORUNDASIN):

      1. PLASTİK ÜRÜN KURALI (EN YÜKSEK ÖNCELİK):
         - Ürün adında, malzeme sütununda veya notlarda şu ifadelerden HERHANGİ BİRİ varsa -> department = "Satınalma"
         - TR: plastik, polimer, pp, polipropilen, pvc, sentetik ayak, plastik ayak
         - RU: пластик, пластиковый, полимер, полипропилен, пвх, пластмасса, пластиковые ножки
         - Plastik ürünler üretilmez, SATIN ALINIR. Marina Hanım'a direkt gider.
         - ÖRNEK: "Пластиковый стул" -> department="Satınalma", "Plastik sandalye" -> department="Satınalma"

      2. KARKAS/İSKELET: "yapılacak", "iskelet", "çerçeve", "каркас", "рама" varsa -> department = "Karkas Üretimi"

      3. DİKİŞHANE VE DÖŞEMEHANE (ÇOK ÖNEMLİ):
         - Kumaş kaplama, dikiş, döşeme gerektiren ürünlerde MUTLAKA İKİ AYRI kalem oluştur:
           a) department = "Dikişhane" (dikiş işi için)
           b) department = "Döşemehane" (döşeme/kaplama işi için)
         - Her ikisi de aynı ürün için ayrı item olarak eklenmelidir.
         - ÖRNEK: Kumaşlı sandalye -> 1 item Dikişhane + 1 item Döşemehane

      4. KUMAŞ TEDARİK: Kumaş adı/kodu varsa -> department = "Kumaş" (Marina Hanım için)

      5. BOYA/CİLA: Boya rengi veya cila notu varsa -> department = "Boyahane"

      6. DİĞER: "Metal Üretimi", "Mobilya Dekorasyon"

      🚨 KRİTİK KURALLAR:
      0. ROW INDEX: Tablodaki "RowIndex" sütunundaki değeri mutlaka her bir "item" için "rowIndex" alanına yaz. Bu, görsellerin doğru eşleşmesi için hayati önem taşır.
      1. ÜRÜN PARÇALAMA: Her bir departman işi için AYRI kalem (item) oluştur.
      2. DETAYLARIN KORUNMASI: Kumaş adı, boya rengi ve tüm teknik notları ilgili TÜM kalemlerin "details" kısmına ekle. Özellikle malzeme türünü (plastik, kumaş, boya) mutlaka details'a yaz.
      3. FABRIC VE PAINT ALANLARI: "fabricDetails" ve "paintDetails" nesnelerini doldur.
      4. MÜŞTERİ BİLGİSİ: "customerName" alanına müşteri adını ve varsa proje adını yaz. Mail içinde "Müşteri:", "Proje:" veya "Ad Soyad:" gibi ifadeleri ara.

      İÇERİK:
      ${fullContent}

      SADECE SAF JSON DÖNDÜR:
      {
        "orderNumber": "...",
        "customerName": "...",
        "items": [
          {
            "product": "[TR] ... / [RU] ...",
            "department": "...",
            "quantity": 0,
            "details": "[TR] ... / [RU] ...",
            "fabricDetails": {"name": "...", "amount": 0},
            "paintDetails": {"name": "..."},
            "source": "Production",
            "rowIndex": 0
          }
        ],
        "deliveryDate": "..."
      }
    `;

      console.log("--- RAW MAIL CONTENT START ---");
      console.log(content);
      console.log("--- RAW MAIL CONTENT END ---");

      if (isExcel) {
        console.log(
          `📊 Excel verisi LLM'e gönderiliyor (${fullContent.length} karakter)`,
        );
      }

      console.log(`🧠 [DEBUG] LLM Parametreleri:`, {
        subject,
        contentLength: fullContent.length,
        contentPreview: fullContent.substring(0, 500),
      });

      const response = await this.llmService.chat(prompt, fullContent);

      console.log(
        `[DEBUG] LLM Raw Response Received: ${response?.substring(0, 500)}...`,
      );
      if (!response) return null;

      // Extract JSON block more robustly
      const jsonMatch = response.match(/\{[\s\S]*\}/);
      if (!jsonMatch) {
        console.error("❌ LLM yanıtında JSON bulunamadı. Ham yanıt:", response);
        return null;
      }

      const jsonStr = jsonMatch[0].trim();
      let parsed;
      try {
        // Log candidate for debugging if needed (shortened)
        // console.log("🔍 JSON Adayı:", jsonStr.substring(0, 500) + "...");

        let cleanJsonStr = jsonStr
          .replace(/[\u0000-\u001F\u007F-\u009F]/g, "") // Remove control characters
          .replace(/\\+"/g, '"') // Fix double escapes
          .trim();

        // Ensure we only have what's between { and }
        const firstBrace = cleanJsonStr.indexOf("{");
        const lastBrace = cleanJsonStr.lastIndexOf("}");
        if (firstBrace !== -1 && lastBrace !== -1) {
          cleanJsonStr = cleanJsonStr.substring(firstBrace, lastBrace + 1);
        }

        parsed = JSON.parse(cleanJsonStr);
      } catch (parseErr) {
        console.error("❌ LLM JSON parse hatası:", parseErr);
        console.error("📄 [KRİTİK] Ham Yanıt (Hata anı):", jsonStr); // FULL RESPONSE FOR DEBUGGING

        if (parseErr instanceof SyntaxError) {
          const match = parseErr.message.match(/at position (\d+)/);
          if (match) {
            const pos = parseInt(match[1]);
            const context = jsonStr.substring(
              Math.max(0, pos - 50),
              Math.min(jsonStr.length, pos + 50),
            );
            console.error(`📍 Hata konumu (${pos}):\n...${context}...`);
          }
        }
        return null;
      }

      console.log(
        `🧠 [DEBUG] LLM Ayrıştırma Başarılı. Ürün Sayısı: ${parsed.items?.length || 0}`,
      );
      console.log(
        `📋 [DEBUG] Ayrıştırılan Ürünler:`,
        JSON.stringify(
          parsed.items?.map((i: OrderItem) => ({
            p: i.product,
            d: i.department,
            r: i.rowIndex,
          })),
          null,
          2,
        ),
      );

      // 🚨 İÇERİK BAZLI MÜKERRER KONTROLÜ
      // Aynı müşteri + benzer ürün kombinasyonunu kontrol et
      const allOrders = this.repository.getAll();
      const customerName = (parsed.customerName || "").toLowerCase().trim();
      const newProducts = (parsed.items || [])
        .map((i: any) =>
          (i.product || "")
            .toLowerCase()
            .replace(/\[tr\].*?\[ru\].*?/gi, "")
            .trim(),
        )
        .sort()
        .join(",");

      // Son 24 saat içindeki aynı müşteri siparişlerini kontrol et
      const oneDayAgo = new Date(
        Date.now() - 24 * 60 * 60 * 1000,
      ).toISOString();
      const recentOrders = allOrders.filter(
        (o: OrderDetail) => o.createdAt > oneDayAgo,
      );

      for (const existingOrder of recentOrders) {
        const existingCustomerName = (existingOrder.customerName || "")
          .toLowerCase()
          .trim();
        const existingProducts = (existingOrder.items || [])
          .map((i: any) =>
            (i.product || "")
              .toLowerCase()
              .replace(/\[tr\].*?\[ru\].*?/gi, "")
              .trim(),
          )
          .sort()
          .join(",");

        // Müşteri adı benzer mi (%80) ve ürün kombinasyonu benzer mi (%70)?
        const customerSimilarity = this.calculateSimilarity(
          customerName,
          existingCustomerName,
        );
        const productSimilarity = this.calculateSimilarity(
          newProducts,
          existingProducts,
        );

        if (customerSimilarity > 0.8 && productSimilarity > 0.7) {
          logger.warn(
            `⚠️ Mükerrer sipariş tespit edildi! Müşteri: "${customerName}" → Mevcut: "${existingCustomerName}" (Benzerlik: ${Math.round(customerSimilarity * 100)}%)`,
          );
          logger.warn(
            `⚠️ Ürün kombinasyonu benzerliği: ${Math.round(productSimilarity * 100)}%`,
          );
          return { ...existingOrder, isDuplicate: true }; // Mevcut siparişi bayrakla döndür
        }
      }

      const order: OrderDetail = {
        id: Date.now().toString(),
        ...parsed,
        status: "new",
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };

      // Kalemleri zenginleştir ve Türkçe kısımları temizle
      order.items = order.items.map((item, index) => {
        let cleanProduct = item.product || "";
        let cleanDetails = item.details || "";

        console.log(`🔍 [STRIP] Orijinal Ürün: "${cleanProduct}"`);

        // Daha agresif temizlik: [RU] kısmını bul ve sonrasını al, veya / işaretinden sonrasını al
        // Dil etiketlerini ve ayraçları temizle
        // [TR] ... / [RU] ... formatından sadece RU kısmını al
        const trRuPatterns = [
          /\[TR\].*?\/.*?\[RU\]\s*(.*)/i,
          /\[TR\].*?\|.*?\[RU\]\s*(.*)/i,
          /\[RU\]\s*(.*)/i,
          /^.*?\/.*?\[RU\]\s*(.*)/i
        ];

        let foundRu = false;
        for (const pattern of trRuPatterns) {
          const match = cleanProduct.match(pattern);
          if (match) {
            cleanProduct = match[1].trim();
            foundRu = true;
            break;
          }
        }

        if (!foundRu && cleanProduct.includes("/")) {
          const parts = cleanProduct.split("/");
          cleanProduct = parts[parts.length - 1].trim();
        }

        // Details için aynısı
        let foundRuDetails = false;
        for (const pattern of trRuPatterns) {
          const match = cleanDetails.match(pattern);
          if (match) {
            cleanDetails = match[1].trim();
            foundRuDetails = true;
            break;
          }
        }

        if (!foundRuDetails && cleanDetails.includes("/")) {
          const parts = cleanDetails.split("/");
          cleanDetails = parts[parts.length - 1].trim();
        }

        // Kalan tagleri temizle (Regex ile)
        cleanProduct = cleanProduct.replace(/\[TR\]|\[RU\]/gi, "").trim();
        cleanDetails = cleanDetails.replace(/\[TR\]|\[RU\]/gi, "").trim();

        console.log(`✅ [STRIP] Temiz Ürün: "${cleanProduct}"`);

        // 🚨 PLASTİK KURALI (Türkçe, Rusça ve İngilizce)
        // Sandalye, ayak veya genel parça plastik ise Satınalma'ya (Marina) gider.
        let finalDept = item.department;
        const lowerProd = (item.product || "").toLowerCase();
        const lowerDetails = (item.details || "").toLowerCase();
        
        // Plastik anahtar kelimeleri (TR + RU + EN)
        const plasticKeywords = [
          "plastik", "пластик", "plastic",
          "полимер", "polimer",
          "полипропилен", "polipropilen", "pp ",
          "пластмасс", "plasmas",
          "пвх", "pvc",
          "пластиковый", "пластиковые", "пластиковая", "пластиковых",
          "синтетик", "sentetik",
        ];
        const isPlastik = plasticKeywords.some(
          (kw) => lowerProd.includes(kw) || lowerDetails.includes(kw),
        );

        if (isPlastik) {
          console.log(
            `🎯 [RULE] Plastik ürün tespit edildi, Satınalma'ya yönlendiriliyor: ${item.product}`,
          );
          finalDept = "Satınalma";
        }

        return {
          ...item,
          product: cleanProduct,
          details: cleanDetails,
          department: finalDept,
          id: `${order.id}_${index}`,
          status: "bekliyor",
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
          fabricDetails: item.fabricDetails
            ? {
                ...item.fabricDetails,
                amount:
                  typeof (item.fabricDetails as any).amount === "string"
                    ? parseFloat(
                        (item.fabricDetails as any).amount.replace(
                          /[^0-9.]/g,
                          "",
                        ),
                      )
                    : (item.fabricDetails as any).amount || 0,
                arrived: false,
              }
            : undefined,
        };
      });

      // Görselleri işle (Eğer Excel verisi varsa)
      if (isExcel && rawExcelData) {
        const floatingImages = (rawExcelData as any).floatingImages as
          | Buffer[]
          | undefined;
        let floatingIndex = 0;

        order.items.forEach((item) => {
          let hasAssignedImage = false;

          // 1. Doğrudan satır numarası eşleşmesi (En güvenilir)
          if (item.rowIndex) {
            const excelMatch = rawExcelData.find(
              (r) => r._rowNumber === item.rowIndex,
            );
            if (excelMatch && excelMatch._imageBuffer) {
              item.imageBuffer = excelMatch._imageBuffer;
              item.imageExtension = excelMatch._imageExtension || "png";
              hasAssignedImage = true;
              console.log(
                `✅ [DEBUG] Resim Eşleşti (RowIndex): Ürün=${item.product}, Satır=${item.rowIndex}`,
              );
            }
          }

          // 2. Satır eşleşmediyse temizlenmiş isim üzerinden ara (Fallback 1)
          if (!hasAssignedImage) {
            const productLower = item.product.toLowerCase();
            const detailsLower = (item.details || "").toLowerCase();

            // Plastik ürünler için özel kontrol (TR, RU ve EN)
            const isImgPlastik = 
              productLower.includes("plastik") || productLower.includes("пластик") || productLower.includes("plastic") ||
              detailsLower.includes("plastik") || detailsLower.includes("пластик") || detailsLower.includes("plastic");

            if (isImgPlastik) {
              console.log(
                `🔍 [IMG] Plastik ürün için görsel eşleştirme deneniyor: ${item.product}`,
              );
              // Floating resim varsa → plastik ürüne ata ve sayacı ilerlet
              if (floatingImages && floatingImages.length > floatingIndex) {
                item.imageBuffer = floatingImages[floatingIndex++]; // ← ++ eklendi!
                item.imageExtension = "png";
                console.log(
                  `✅ [IMG] Plastik ürün için floating görsel atandı (index: ${floatingIndex - 1}).`,
                );
                hasAssignedImage = true;
              } else {
                console.log(
                  `⚠️ [IMG] Plastik ürün için floating görsel bulunamadı (Excel'de resim yok mu?): ${item.product}`,
                );
              }
            }

            // Genel isim eşleşmesi (plastik değilse veya floating yoksa)
            if (!hasAssignedImage) {
              const nameMatch = rawExcelData.find((r) => {
                const col3 = String(r.Col3 || "").toLowerCase();
                return (
                  col3.includes(productLower) || productLower.includes(col3)
                );
              });
              if (nameMatch && nameMatch._imageBuffer) {
                item.imageBuffer = nameMatch._imageBuffer;
                item.imageExtension = nameMatch._imageExtension || "png";
                hasAssignedImage = true;
                console.log(
                  `✅ [DEBUG] Resim Eşleşti (NameMatch): Ürün=${item.product}`,
                );
              }
            }
          }

          // 3. Satırdan resim eşleşmediyse floating (serbest) resimlerden birini ata (Fallback 2)
          if (
            !hasAssignedImage &&
            floatingImages &&
            floatingIndex < floatingImages.length
          ) {
            item.imageBuffer = floatingImages[floatingIndex++];
            item.imageExtension = "png";
            console.log(
              `✅ [DEBUG] Serbest Resim (Fallback) Eşleşti: Ürün=${item.product}, Kalan Serbest Resim=${floatingImages.length - floatingIndex}`,
            );
          } else if (!hasAssignedImage) {
            console.log(`⚠️ [DEBUG] Resim Bulunamadı: Ürün=${item.product}`);
          }

          // internet URL'lerini temizle - önceliğimiz her zaman Excel dosyası
          delete item.imageUrl;
        });
      }

      await this.repository.save(order);

      // Görsel hafıza - Artık ana sipariş DB'de olduğu için güvenle çalışabilir
      try {
        await this.saveToVisualMemory(order);
      } catch (e) {
        console.error("⚠️ Görsel hafıza kaydı atlandı (hata):", e);
      }

      await this.logOrder(order);
      return order;
    } catch (error) {
      console.error("❌ Sipariş ayrıştırma hatası:", error);
      return null;
    }
  }

  /**
   * Doğrudan bir Excel buffer'ını sipariş olarak işler.
   * Barış Bey'den gelen Excel'lerin otomatik sipariş olarak işlenmesi için kullanılır.
   */
  async processExcelOrder(buffer: Buffer, _uid: string): Promise<OrderDetail | null> {
    try {
      logger.info("📊 Doğrudan Excel sipariş işleme başlatılıyor...");
      const parsed = await parseOrderExcel(buffer);

      if (!parsed) {
        logger.warn("⚠️ Excel parser sonuç döndürmedi.");
        return null;
      }

      const { order: excelOrder } = parsed;

      // Mükerrer kontrolü
      const allOrders = this.repository.getAll();
      const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
      const recentOrders = allOrders.filter((o: OrderDetail) => o.createdAt > oneDayAgo);

      for (const existing of recentOrders) {
        if (
          excelOrder.orderNumber &&
          existing.orderNumber === excelOrder.orderNumber
        ) {
          logger.warn(`⚠️ Mükerrer sipariş (no eşleşti): ${excelOrder.orderNumber}`);
          return { ...existing, isDuplicate: true } as any;
        }
      }

      excelOrder.createdAt = new Date().toISOString();
      excelOrder.updatedAt = new Date().toISOString();

      await this.repository.save(excelOrder);

      try { await this.saveToVisualMemory(excelOrder); } catch (_) {}
      await this.logOrder(excelOrder);

      logger.info(
        { orderNumber: excelOrder.orderNumber, items: excelOrder.items.length },
        "✅ Doğrudan Excel işleme ile sipariş oluşturuldu",
      );
      return excelOrder;
    } catch (err) {
      logger.error({ err }, "❌ Doğrudan Excel işleme hatası");
      return null;
    }
  }

  /**
   * Görsel bir özet tablo oluşturur.
   */
  getVisualSummary(order: OrderDetail, lang: Language = "tr"): string {
    const title = t("summary_title", lang);
    let summary = `${title} (${order.customerName})\n`;
    summary += `--------------------------------------------\n`;

    // Gruplandırma
    const stockItems = order.items.filter((i) => i.source === "Stock");
    const prodItems = order.items.filter((i) => i.source === "Production");
    const extItems = order.items.filter((i) => i.source === "External");

    if (stockItems.length > 0) {
      summary +=
        `${t("stock_delivery", lang)}\n` +
        stockItems
          .map((i) => `- ${i.product} (${i.quantity} adet)`)
          .join("\n") +
        `\n\n`;
    }
    if (prodItems.length > 0) {
      summary +=
        `${t("production_entry", lang)}\n` +
        prodItems
          .map(
            (i) =>
              `- ${i.product} (${i.quantity} adet) -> *${this.getDeptTranslation(i.department, lang)}* (${i.department})`,
          )
          .join("\n") +
        `\n\n`;
    }
    if (extItems.length > 0) {
      summary +=
        `${t("external_purchase", lang)}\n` +
        extItems.map((i) => `- ${i.product} (${i.quantity} adet)`).join("\n") +
        `\n\n`;
    }

    summary += `📅 *${t("delivery_label", lang)}:* ${order.deliveryDate}\n`;
    summary += `${t("coordinator_note", lang)}`;

    return summary;
  }

  getRoutingMentions(order: OrderDetail): string {
    let mentions = "";
    const departments = Array.from(
