  private calculateSimilarity(s1: string, s2: string): number {
    let longer = s1;
    let shorter = s2;
    if (s1.length < s2.length) {
      longer = s2;
      shorter = s1;
    }
    const longerLength = longer.length;
    if (longerLength === 0) {
      return 1.0;
    }
    return (longerLength - this.editDistance(longer, shorter)) / longerLength;
  }

  private editDistance(s1: string, s2: string): number {
    s1 = s1.toLowerCase();
    s2 = s2.toLowerCase();

    const costs = new Array();
    for (let i = 0; i <= s1.length; i++) {
      let lastValue = i;
      for (let j = 0; j <= s2.length; j++) {
        if (i == 0) costs[j] = j;
        else {
          if (j > 0) {
            let newValue = costs[j - 1];
            if (s1.charAt(i - 1) != s2.charAt(j - 1))
              newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
            costs[j - 1] = lastValue;
            lastValue = newValue;
          }
        }
      }
      if (i > 0) costs[s2.length] = lastValue;
    }
    return costs[s2.length];
  }
}

import fs from "fs";
import path from "path";
import os from "os";
import { logger } from "./logger";

export class SelfCleanupService {
  /**
   * Sistemsel temizlik yapar: Geçici dosyalar, test scriptleri ve loglar.
   */
  public static async performCleanup(): Promise<{ success: boolean; deletedItems: string[] }> {
    const deletedItems: string[] = [];
    const baseDir = process.cwd();
    const utilsDir = path.join(baseDir, "src", "utils");

    try {
      // 1. Test Scriptlerini Temizle (src/utils/test-*.ts ve check-*.ts)
      if (fs.existsSync(utilsDir)) {
        const files = fs.readdirSync(utilsDir);
        for (const file of files) {
          if (file.startsWith("test-") || file.startsWith("check-") || file.endsWith("-test.ts")) {
            const filePath = path.join(utilsDir, file);
            fs.unlinkSync(filePath);
            deletedItems.push(`Script: ${file}`);
          }
        }
      }

      // 2. Geçici Ses Dosyalarını Temizle (/tmp içindeki voice_*)
      const tempDir = os.tmpdir();
      const tempFiles = fs.readdirSync(tempDir);
      for (const file of tempFiles) {
        if (file.startsWith("voice_") && (file.endsWith(".ogg") || file.endsWith(".mp3"))) {
          const filePath = path.join(tempDir, file);
          try {
            fs.unlinkSync(filePath);
            deletedItems.push(`Temp: ${file}`);
          } catch (e) {
            // Dosya o an kullanılıyor olabilir, geç
          }
        }
      }

      // 3. Kök dizindeki geçici/test dosyalarını temizle
      const rootFiles = [
        "check-db-counts.js", 
        "cleanup-db.js", 
        "db2.txt", 
        "db_err.txt", 
        "output.txt", 
        "report_output.txt", 
        "test-output.png", 
        "test-pdf-view.ts", 
        "verify_db_output.txt", 
        "verify_results.txt"
      ];
      for (const file of rootFiles) {
        const filePath = path.join(baseDir, file);
        if (fs.existsSync(filePath)) {
          fs.unlinkSync(filePath);
          deletedItems.push(`Root: ${file}`);
        }
      }

      // 4. Diğer özel scriptleri temizle (src/utils içinde)
      const specialScripts = ["full-cleanup.ts", "list-recent-uids.ts", "verify-db.ts", "reset-mail-flag.ts", "clear-gmail.ts", "analyze-dump.ts"];
      for (const script of specialScripts) {
        const scriptPath = path.join(utilsDir, script);
        if (fs.existsSync(scriptPath)) {
          fs.unlinkSync(scriptPath);
          deletedItems.push(`Script: ${script}`);
        }
      }

      // 5. Yerel Veri Dosyalarını Sıfırla (Loglar)
      const logFile = path.join(baseDir, "data", "verilen_siparisler.log");
      if (fs.existsSync(logFile)) {
        fs.writeFileSync(logFile, "");
        deletedItems.push("Log: verilen_siparisler.log (sıfırlandı)");
      }

      logger.info({ deletedCount: deletedItems.length }, "✨ Self-cleanup başarıyla tamamlandı.");
      return { success: true, deletedItems };
    } catch (error: any) {
      logger.error({ error: error.message }, "❌ Self-cleanup sırasında hata oluştu.");
      return { success: false, deletedItems };
    }
  }
}

import fs from "fs";
import path from "path";
import os from "os";
import { Context } from "grammy";
import OpenAI from "openai";
import * as dotenv from "dotenv";
import { logger } from "./logger";

dotenv.config();

export class VoiceService {
  private openai: OpenAI | null = null;
  private readonly MODEL = "google/gemini-2.0-flash-001"; // OpenRouter'da ses işleme için en hızlı ve stabil model

  constructor() {
    const apiKey = process.env.OPENROUTER_API_KEY?.trim();

    if (apiKey) {
      logger.info(
        { keyStart: apiKey.substring(0, 8) + "..." }, 
        "🔑 OpenRouter API (Voice: Gemini) yüklendi."
      );
      this.openai = new OpenAI({
        apiKey: apiKey,
        baseURL: "https://openrouter.ai/api/v1",
        timeout: 60000,
      });
    } else {
      logger.error("❌ OPENROUTER_API_KEY bulunamadı!");
    }
  }

  public async transcribeVoiceMessage(
    ctx: Context,
    fileId: string,
    lang: string = "auto",
  ): Promise<string | null> {
    if (!this.openai) {
      logger.error("❌ OpenRouter API eksik! Sesli mesaj işlenemez.");
      return null;
    }

    let tempFilePath: string | null = null;
    try {
      logger.info({ fileId }, "🎙️ Sesli mesaj indirme başladı...");

      const file = await ctx.api.getFile(fileId);
      if (!file.file_path) throw new Error("Telegram dosya yolu bulunamadı");

      // Geçici dosya yolu
      const tempFileName = `voice_${Date.now()}_${fileId}.ogg`;
      tempFilePath = path.join(os.tmpdir(), tempFileName);

      // Telegram'dan dosyayı indir
      const fileUrl = `https://api.telegram.org/file/bot${process.env.TELEGRAM_BOT_TOKEN}/${file.file_path}`;

      const https = require('https');
      await new Promise((resolve, reject) => {
        const fileStream = fs.createWriteStream(tempFilePath!);
        https.get(fileUrl, (res: any) => {
          if (res.statusCode !== 200) return reject(new Error(`Download failed: ${res.statusCode}`));
          res.pipe(fileStream);
          fileStream.on('finish', () => {
            fileStream.close();
            resolve(true);
          });
        }).on('error', (err: any) => {
          if (fs.existsSync(tempFilePath!)) fs.unlinkSync(tempFilePath!);
          reject(err);
        });
      });

      // Dosyayı oku ve Base64'e çevir (OpenRouter multimodal için bu formatı tercih eder)
      const audioBuffer = fs.readFileSync(tempFilePath);
      const base64Audio = audioBuffer.toString('base64');

      logger.info({ size: audioBuffer.length }, "📁 Ses dosyası Base64 formatına çevrildi. OpenRouter'a (Gemini) gönderiliyor...");

      // Chat Completions API üzerinden sesli mesajı metne çevir/analiz et
      const response = await this.openai.chat.completions.create({
        model: this.MODEL,
        messages: [
          {
            role: "user",
            content: [
              {
                type: "text",
                text: "Lütfen bu sesli mesajı aynen kelimesi kelimesine metne dök. Sorumluluk al ve sadece konuşulanları yaz."
              },
              {
                type: "image_url", // OpenRouter multimodal standartlarında genellikle bu yapı kullanılır veya input_audio
                image_url: {
                  url: `data:audio/ogg;base64,${base64Audio}`
                }
              }
            ]
          }
        ]
      } as any);

      const result = response.choices[0]?.message?.content;
      if (result) {
        logger.info({ text: result.substring(0, 50) + "..." }, "✅ Transcription başarılı (OpenRouter/Gemini).");
        return result;
      }

      logger.warn("⚠️ OpenRouter'dan metin dönmedi.");
      return null;
    } catch (error: any) {
      const errorMessage = error.response?.data?.error?.message || error.message;
      logger.error({ 
        error: errorMessage,
        status: error.status,
        fileId 
      }, "❌ Sesli mesaj çeviri hatası (OpenRouter/Gemini)");
      return null;
    } finally {
      if (tempFilePath && fs.existsSync(tempFilePath)) {
        try { fs.unlinkSync(tempFilePath); } catch (e) {}
      }
    }
  }
}
